  app2.get("/admin/kyc-document/:id", authMiddleware2, adminMiddleware2, async (c4) => {
    const prisma = c4.get("getPrisma")(c4.env);
    const id = c4.req.param("id");
    const expires = c4.req.query("expires");
    const token = c4.req.query("token");
    if (!await verifySignedKycUrlWorker(id, expires, token, c4.env)) {
      return c4.json({ error: "Forbidden: Invalid or expired signature" }, 403);
    }
    const doc = await prisma.kycDocument.findUnique({ where: { id } });
    if (!doc || !doc.documentUrl) return c4.json({ error: "Not found" }, 404);
    const rawUrl = doc.documentUrl;
    try {
      const res = await fetch(rawUrl);
      if (!res.ok) return c4.json({ error: "Failed to fetch document" }, 500);
      const contentType = res.headers.get("content-type") || "application/octet-stream";
      const buffer = await res.arrayBuffer();
      return new Response(buffer, {
        headers: {
          "Content-Type": contentType,
          "Cache-Control": "private, max-age=3600"
        }
      });
    } catch (err) {
      return c4.json({ error: "Failed to proxy document: " + err.message }, 500);
    }
  });
  app2.get("/admin/kyc-image/:id", authMiddleware2, adminMiddleware2, async (c4) => {
    const prisma = c4.get("getPrisma")(c4.env);
    const id = c4.req.param("id");
    const expires = c4.req.query("expires");
    const token = c4.req.query("token");
    if (!await verifySignedKycUrlWorker(id, expires, token, c4.env)) {
      return c4.json({ error: "Forbidden: Invalid or expired signature" }, 403);
    }
    let idImage = null;
    const guide = await prisma.guideProfile.findUnique({ where: { id } });
    if (guide && guide.idImage) {
      idImage = decrypt(guide.idImage);
    } else {
      const user = await prisma.user.findUnique({ where: { id } });
      if (user && user.idImage) {
        idImage = decrypt(user.idImage);
      }
    }
    if (!idImage) {
      return c4.json({ error: "KYC Document not found" }, 404);
    }
    const transform2 = c4.req.query("transform");
    let redirectUrl = idImage;
    if (transform2 && redirectUrl.includes("cloudinary.com")) {
      redirectUrl = redirectUrl.replace("/upload/", `/upload/${transform2}/`);
    }
    return c4.redirect(redirectUrl);
  });
  app2.get("/admin/audit-logs", authMiddleware2, adminMiddleware2, async (c4) => {
    const prisma = c4.get("getPrisma")(c4.env);
    const page = Math.max(1, parseInt(c4.req.query("page") || "1"));
    const limit = Math.min(100, Math.max(1, parseInt(c4.req.query("limit") || "50")));
    const skip2 = (page - 1) * limit;
    try {
      const [verificationAudits, generalAudits] = await Promise.all([
        prisma.verificationAudit.findMany({ orderBy: { createdAt: "desc" }, take: skip2 + limit }),
        prisma.auditLog.findMany({ orderBy: { createdAt: "desc" }, take: skip2 + limit, include: { admin: { select: { name: true } } } })
      ]);
      const unifiedAudits = [
        ...verificationAudits.map((v4) => ({
          id: v4.id,
          type: "VERIFICATION",
          adminId: v4.adminId,
          adminName: v4.adminName,
          targetUserId: v4.targetUserId,
          targetName: v4.targetName,
          action: v4.action,
          previousStatus: v4.previousStatus,
          newStatus: v4.newStatus,
          ipAddress: v4.ipAddress,
          userAgent: v4.userAgent,
          createdAt: v4.createdAt
        })),
        ...generalAudits.map((g3) => ({
          id: g3.id,
          type: "SYSTEM",
          adminId: g3.adminId,
          adminName: g3.admin?.name || "Admin",
          targetUserId: null,
          targetName: "System",
          action: g3.action,
          previousStatus: null,
          newStatus: JSON.stringify(g3.details)?.substring(0, 50) || "N/A",
          ipAddress: g3.ipAddress,
          userAgent: g3.userAgent,
          createdAt: g3.createdAt
        }))
      ];
      unifiedAudits.sort((a3, b6) => new Date(b6.createdAt) - new Date(a3.createdAt));
      const totalCount = unifiedAudits.length;
      const paginatedLogs = unifiedAudits.slice(skip2, skip2 + limit);
      return c4.json({
        data: paginatedLogs,
        page,
        limit,
        totalCount,
        totalPages: Math.ceil(totalCount / limit)
      });
    } catch (err) {
      return c4.json({ error: err.message }, 500);
    }
  });
