app.get("/resorts", discoveryCache, async (c4) => {
  const prisma = getPrisma(c4.env);
  const {
    minPrice,
    maxPrice,
    type,
    category,
    minRating,
    sort,
    search,
    guests,
    checkIn,
    checkOut
  } = c4.req.query();
  try {
    let categoriesQuery = [];
    if (category) {
      if (Array.isArray(category)) {
        categoriesQuery = category;
      } else if (typeof category === "string") {
        if (category.startsWith("[") && category.endsWith("]")) {
          try {
            categoriesQuery = JSON.parse(category);
          } catch (e3) {
            categoriesQuery = category.split(",").map((x6) => x6.trim()).filter(Boolean);
          }
        } else {
          categoriesQuery = category.split(",").map((x6) => x6.trim()).filter(Boolean);
        }
      }
    }
    let checkInDate, checkOutDate;
    if (checkIn && checkOut) {
      checkInDate = new Date(checkIn);
      checkOutDate = new Date(checkOut);
    }
    const where = {
      status: "ACTIVE",
      owner: { isVerified: true },
      ...minPrice || maxPrice ? {
        pricePerNight: {
          ...minPrice ? { gte: parseFloat(minPrice) } : {},
          ...maxPrice ? { lte: parseFloat(maxPrice) } : {}
        }
      } : {},
      ...type ? { type } : {},
      ...categoriesQuery.length > 0 ? {
        categories: {
          hasEvery: categoriesQuery
        }
      } : {},
      ...minRating ? { rating: { gte: parseFloat(minRating) } } : {},
      // Capacity Filtering (Dates checked in memory later)
      ...guests ? {
        roomTypes: {
          some: {
            capacity: { gte: parseInt(guests, 10) }
          }
        }
      } : {}
    };
    const orderBy = {};
    if (sort === "price_asc") orderBy.pricePerNight = "asc";
    else if (sort === "price_desc") orderBy.pricePerNight = "desc";
    else if (sort === "rating") orderBy.rating = "desc";
    else if (sort === "newest") orderBy.createdAt = "desc";
    else orderBy.reviewCount = "desc";
    const resorts = await prisma.resort.findMany({
      where,
      orderBy,
      select: {
        id: true,
        slug: true,
        name: true,
        tagline: true,
        type: true,
        locationArea: true,
        images: true,
        amenities: true,
        rating: true,
        reviewCount: true,
        pricePerNight: true,
        categories: true,
        isVerified: true,
        isFeatured: true,
        roomTypes: checkInDate && checkOutDate ? {
          select: {
            availableCount: true,
            capacity: true,
            bookings: {
              where: {
                status: { in: ["CONFIRMED", "PAID", "PENDING"] },
                checkIn: { lt: checkOutDate },
                checkOut: { gt: checkInDate }
              }
            },
            blockings: {
              where: {
                date: {
                  gte: checkInDate,
                  lt: checkOutDate
                }
              }
            }
          }
        } : false
      },
      cacheStrategy: { swr: 60, ttl: 60 }
      // Cache at the edge for 60s
    });
    let filteredResorts = resorts;
    if (search) {
      const searchLower = search.toLowerCase();
      filteredResorts = resorts.filter(
        (r3) => r3.name.toLowerCase().includes(searchLower) || r3.locationArea.toLowerCase().includes(searchLower) || r3.tagline.toLowerCase().includes(searchLower) || (r3.categories || []).some((cat) => cat.toLowerCase().includes(searchLower))
      );
    }
    let finalResorts = filteredResorts;
    if (checkInDate && checkOutDate) {
      finalResorts = filteredResorts.filter((r3) => {
        if (!r3.roomTypes || r3.roomTypes.length === 0) return false;
        return r3.roomTypes.some((rt) => {
          if (guests && rt.capacity < parseInt(guests, 10)) return false;
          const overlappingBookings = rt.bookings.length;
          const overlappingBlockings = rt.blockings.length;
          const availableInventory = rt.availableCount - overlappingBookings - overlappingBlockings;
          return availableInventory > 0;
        });
      });
    }
    const optimizedResorts = finalResorts.map((r3) => {
      const copy = { ...r3 };
      delete copy.roomTypes;
      return {
        ...copy,
        category: r3.categories[0] || null,
        images: r3.images.slice(0, 1)
      };
    });
    return c4.json(optimizedResorts);
  } catch (err) {
    return c4.json({ error: err.message }, 500);
  }
});
