app.post("/reviews", authMiddleware, async (c4) => {
  const prisma = getPrisma(c4.env);
  const payload = c4.get("user");
  const userId = payload.userId;
  try {
    const data = await c4.req.json();
    const { resortId, rating, comment } = data;
    if (!resortId || !rating || !comment) {
      return c4.json({ error: "Resort ID, rating, and comment are required" }, 400);
    }
    const ratingVal = parseInt(rating);
    if (isNaN(ratingVal) || ratingVal < 1 || ratingVal > 5) {
      return c4.json({ error: "Rating must be between 1 and 5" }, 400);
    }
    const resort = await prisma.resort.findUnique({ where: { id: resortId } });
    if (!resort) return c4.json({ error: "Resort not found" }, 404);
    const validBooking = await prisma.booking.findFirst({
      where: {
        userId,
        resortId,
        status: { in: ["CHECKED_IN", "COMPLETED"] }
      }
    });
    if (!validBooking) {
      return c4.json({ error: "You can only leave a review for resorts you have checked into or completed a stay with" }, 403);
    }
    const review = await prisma.review.create({
      data: {
        resortId,
        userId,
        rating: ratingVal,
        comment: comment.trim()
      },
      include: { user: { select: { name: true, email: true } } }
    });
    const aggregates = await prisma.review.aggregate({
      where: { resortId },
      _avg: { rating: true },
      _count: { id: true }
    });
    const averageRating = parseFloat((aggregates._avg.rating || ratingVal).toFixed(1));
    const totalReviews = aggregates._count.id || 1;
    await prisma.resort.update({
      where: { id: resortId },
      data: { rating: averageRating, reviewCount: totalReviews }
    });
    return c4.json(review, 201);
  } catch (err) {
    return c4.json({ error: err.message }, 500);
  }
});
