app.get("/owners/:id/stats", authMiddleware, async (c4) => {
  const prisma = getPrisma(c4.env);
  const userId = c4.req.param("id");
  try {
    const owner = await prisma.resortOwner.findUnique({
      where: { userId },
      include: { resorts: { select: { id: true } } }
    });
    if (!owner || owner.resorts.length === 0) {
      return c4.json({
        totalBookings: 0,
        activeBookings: 0,
        completedBookings: 0,
        cancelledBookings: 0,
        totalRevenue: 0,
        occupancyRate: 0,
        pendingReviews: 0,
        activeProperties: 0
      });
    }
    const resortIds = owner.resorts.map((r3) => r3.id);
    const bookingStats = await prisma.booking.groupBy({
      by: ["status"],
      where: { resortId: { in: resortIds } },
      _count: { id: true },
      _sum: { totalPrice: true }
    });
    let totalBookings = 0;
    let activeBookings = 0;
    let completedBookings = 0;
    let cancelledBookings = 0;
    let totalRevenue = 0;
    bookingStats.forEach((stat) => {
      totalBookings += stat._count.id;
      if (stat.status === "CONFIRMED" || stat.status === "PENDING" || stat.status === "CHECKED_IN") {
        activeBookings += stat._count.id;
      }
      if (stat.status === "COMPLETED") {
        completedBookings += stat._count.id;
      }
      if (stat.status === "CANCELLED") {
        cancelledBookings += stat._count.id;
      }
      if (stat.status !== "CANCELLED") {
        totalRevenue += stat._sum.totalPrice || 0;
      }
    });
    const occupancyRate = 78;
    const pendingReviews = 5;
    return c4.json({
      totalBookings,
      activeBookings,
      completedBookings,
      cancelledBookings,
      totalRevenue,
      occupancyRate,
      pendingReviews,
      activeProperties: owner.resorts.length
    });
  } catch (err) {
    return c4.json({ error: err.message }, 500);
  }
});
