app.get("/upload/signature", authMiddleware, async (c4) => {
  try {
    const uploadType = c4.req.query("type") || "default";
    const timestamp = Math.round((/* @__PURE__ */ new Date()).getTime() / 1e3).toString();
    const folder = uploadType === "kyc" ? "hampi-stays/kyc" : "hampi-stays";
    const apiSecret = c4.env.CLOUDINARY_API_SECRET;
    if (!apiSecret) {
      return c4.json({ error: "CLOUDINARY_API_SECRET is not configured" }, 500);
    }
    let eager = "";
    let paramsToSign = { folder, timestamp };
    if (uploadType === "kyc") {
      paramsToSign.type = "authenticated";
    }
    if (uploadType === "resort" || uploadType === "room") {
      eager = "c_fill,w_300,h_200,f_auto,q_auto|c_fill,w_800,h_600,f_auto,q_auto|c_fill,w_1200,h_800,f_auto,q_auto";
      paramsToSign.eager = eager;
    }
    const signString = Object.keys(paramsToSign).sort().map((k5) => `${k5}=${paramsToSign[k5]}`).join("&") + apiSecret;
    const encoder = new TextEncoder();
    const data = encoder.encode(signString);
    const hashBuffer = await crypto6.subtle.digest("SHA-1", data);
    const hashArray = Array.from(new Uint8Array(hashBuffer));
    const signature = hashArray.map((b6) => b6.toString(16).padStart(2, "0")).join("");
    return c4.json({
      signature,
      timestamp,
      cloud_name: c4.env.CLOUDINARY_CLOUD_NAME,
      api_key: c4.env.CLOUDINARY_API_KEY,
      folder,
      eager,
      type: paramsToSign.type || void 0
    });
  } catch (err) {
    console.error("Upload signature error:", err);
    return c4.json({ error: "Failed to generate upload signature: " + err.message }, 500);
  }
});
app.post("/upload/check-hash", authMiddleware, async (c4) => {
  try {
    const { hash: hash3, url: url2 } = await c4.req.json();
    if (!hash3) return c4.json({ error: "Hash required" }, 400);
    const prisma = getPrisma(c4.env);
    const existing = await prisma.mediaHash.findUnique({
      where: { hash: hash3 }
    });
    if (existing) {
      return c4.json({ exists: true, message: "This image has already been uploaded." });
    }
    if (url2) {
      await prisma.mediaHash.create({
        data: {
          hash: hash3,
          url: url2,
          userId: c4.get("userId")
        }
      });
      return c4.json({ exists: false, saved: true });
    }
    return c4.json({ exists: false });
  } catch (err) {
    console.error("Check hash error:", err);
    return c4.json({ error: "Failed to check media hash" }, 500);
  }
});
