app.get("/guides/recommended", async (c4) => {
  const prisma = getPrisma(c4.env);
  const { checkIn, checkOut } = c4.req.query();
  try {
    let guides = await prisma.guideProfile.findMany({
      where: {
        status: "APPROVED",
        isActive: true,
        isVerified: true
      },
      include: {
        user: { select: { id: true, name: true, avatar: true } },
        bookings: { select: { date: true, durationHours: true, status: true } }
      }
    });
    if (checkIn && checkOut) {
      const start = new Date(checkIn);
      const end = new Date(checkOut);
      guides = guides.filter((guide) => {
        const isBlocked = guide.blockedDates.some((d5) => {
          const bDate = new Date(d5);
          return bDate >= start && bDate <= end;
        });
        if (isBlocked) return false;
        const hasOverlap = guide.bookings.some((b6) => {
          if (b6.status !== "CONFIRMED" && b6.status !== "PENDING") return false;
          const bStart = new Date(b6.date);
          const bEnd = new Date(bStart.getTime() + b6.durationHours * 60 * 60 * 1e3);
          return start < bEnd && end > bStart;
        });
        if (hasOverlap) return false;
        return true;
      });
    }
    guides.sort((a3, b6) => {
      if (b6.rating !== a3.rating) return b6.rating - a3.rating;
      return b6.reviewCount - a3.reviewCount;
    });
    const topGuides = guides.slice(0, 3).map((g3) => {
      const { bookings, blockedDates, fraudFlags, ...safeGuide } = g3;
      return safeGuide;
    });
    return c4.json(topGuides);
  } catch (err) {
    return c4.json({ error: err.message }, 500);
  }
});
